external_knowledge:
- "large, wandering beacon signals" refers to DNS request packets with a size greater than 1000 bytes;
- "origins" refers to the source MAC address;
- "landing spots" refer to the capture location;
- "intercepted multiple times" indicates that there are more than one event records of type 'capture' for the packet;
- "through the murky depths of the network" metaphorically refers to the network where packets are captured and analyzed.

sql:
SELECT alarm_id, alarm_time, alarm_description, alarm_status
FROM alarms
WHERE alarm_status = 'active';

SELECT packets.packet_id, packet_types.packet_type_name
FROM packets
JOIN packet_types ON packets.packet_type_id = packet_types.packet_type_id;

SELECT p.source_ip, p.dest_ip, p.purpose, ne.event_description
FROM packets p
JOIN network_events ne ON p.packet_id = ne.packet_id;

SELECT source_ip
FROM packets
WHERE packet_size = (SELECT MAX(packet_size) FROM packets);

SELECT purpose, AVG(packet_size) AS avg_packet_size
FROM packets
GROUP BY purpose;

SELECT
  COUNT(CASE WHEN alarm_description LIKE '%suspicious activity%' AND alarm_status = 'active' THEN 1 END) * 1.0 / COUNT(*) AS ratio_active_suspicious_alarms
FROM alarms;

SELECT COUNT(*) 
FROM user_activities 
WHERE user_id = '0';

SELECT packet_id, purpose
FROM packets
WHERE packet_capture_location = '1' AND protocol_id = '1' AND packet_id = '1';

